	GetByExternalID(ctx context.Context, externalID string) (userID string, orgID *string, err error)
}

// UserLookup returns middleware that resolves the JWT external ID to internal
// user and org IDs via a database lookup. Apply after JWTMiddleware on routes
// that need ContextKeyUserID or ContextKeyOrgID.
//
// If the user is not found (first login), the middleware continues without
// setting these keys — the /auth/callback handler handles user creation.
func UserLookup(resolver UserResolver) gin.HandlerFunc {
	return func(c *gin.Context) {
		externalID := c.GetString(string(ContextKeyExternalID))
		if externalID == "" {
			c.Next()
			return
		}
		userID, orgID, err := resolver.GetByExternalID(c.Request.Context(), externalID)
		if err != nil {
			// User not found = first login, let auth callback handle creation
			c.Next()
			return
		}
		c.Set(string(ContextKeyUserID), userID)
		if orgID != nil {
			c.Set(string(ContextKeyOrgID), *orgID)
		}
		c.Next()
	}
}
```

You need to add `"context"` to the imports if not already there (it should be).

## Problem 2: Wire UserLookup in main.go

In `cmd/api/main.go`, after `api.Use(middleware.JWTMiddleware(&cfg.Zitadel))` (line 434), add:

```go
api.Use(middleware.UserLookup(&userLookupAdapter{repo: userRepo}))
```

And add an adapter struct near the top of main.go (near the other adapters like `securityEvaluatorAdapter`):

```go
// userLookupAdapter bridges UserRepository to the middleware.UserResolver interface.
type userLookupAdapter struct {
	repo *repository.UserRepository
}

func (a *userLookupAdapter) GetByExternalID(ctx context.Context, externalID string) (string, *string, error) {
	u, err := a.repo.GetByExternalID(ctx, externalID)
	if err != nil {
		return "", nil, err
	}
	return u.ID, u.OrgID, nil
}
```

## Problem 3: auth handler error handling

In `internal/handler/auth.go`, the `Callback` handler treats ALL errors from `GetByExternalID` as "user not found". It should specifically check for not-found errors:

Read the current file and update the error handling to distinguish not-found from actual errors:
```go
user, err := h.svc.GetByExternalID(c.Request.Context(), externalIDStr)
if err != nil {
    // Check if it's a not-found error — create new user
    // Otherwise, return 500
}
```

Check how `apierror.NewNotFound` works in the codebase and use the appropriate error check.

